var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"3종 침식체라......","JPN":"第3種侵食体か……","ENG":"Category 3, huh...","TWN":"3類侵蝕體……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"......우스꽝스러울 만큼 손쉽게 쓰러뜨렸군.","JPN":"……あっけないくらい簡単に倒したな。","ENG":"That was ridiculously easy...","TWN":"……輕而易舉就打倒了，這一切真是可笑。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"이게...... 그 녀석이 말했던 <color=#ffd34c>자매</color>인가......?","JPN":"これが……あいつが言った<color=#ffd34c>姉妹</color>の力なのか……？","ENG":"So is this... what she meant by becoming a <color=#ffd34c>sister</color>?","TWN":"這……就是那傢伙說的<color=#ffd34c>姐妹</color>嗎……？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"확실히 뭔가 대단한 존재라도 된 것 같은 기분이야.","JPN":"確かに我ながら何か凄い存在になったような気分だ。","ENG":"I definitely feel like I've become something special.","TWN":"確實感覺力量變強了。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"수정이 몸 속으로 파고들 때는...... 그렇게나 고통스러웠는데......","JPN":"水晶が体内に食い込む時は……あんなに苦しかったのに……","ENG":"Although it was agonizing... when the crystal dug into my body...","TWN":"雖然水晶進入身體的時候……是那麼痛苦……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"하아...... 윽......","JPN":"はあ……うっ……","ENG":"Ah... Ugh...","TWN":"哈啊……呃……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"정신 차려, 꼬맹이.","JPN":"しっかりしろ、ガキ。","ENG":"Get yourself together, kid.","TWN":"打起精神來，小鬼。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"주위를 둘러 봐. 이제 침식체는 더 이상 남아 있지 않아.","JPN":"周りを見ろ。もう侵食体は残っていない。","ENG":"Look around. There aren't any C.O.s left.","TWN":"看看周圍，現在已經沒有侵蝕體了。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니......?","JPN":"リタお姉ちゃん……？","ENG":"Rita?","TWN":"麗塔姐姐……？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"정말...... 리타 언니예요......?","JPN":"本当に……リタお姉ちゃんですか？","ENG":"Is that... really you, Rita?","TWN":"真的是……是麗塔姐姐……？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"......그래. 이런 모습으로 나타났으니 못 믿겠지만.","JPN":"……そうだ。こんな姿になって信じがたいと思うが。","ENG":"Yeah. Though I guess I can't blame you for not believing me, given how I look.","TWN":"……嗯。我現在這個樣子，你應該會有點難以置信吧。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"별로 어울리지는 않지?","JPN":"似合ってないだろ？","ENG":"It doesn't suit me very well, does it?","TWN":"不太合適是不是？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"아뇨......","JPN":"……いいえ。","ENG":"Oh it does...","TWN":"沒有……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"아니에요, 리타 언니.","JPN":"いいえ、リタお姉ちゃん。","ENG":"You look great, Rita.","TWN":"不，麗塔姐姐。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"예전이나 지금이나...... 언니는 예뻐요.","JPN":"昔も今も……お姉ちゃんは綺麗です。","ENG":"Like always... you're beautiful.","TWN":"不管是之前還是現在……姐姐都很美。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"조금만 참아. 상처를 치료해 줄게.","JPN":"少しだけ我慢しろ。傷を癒してやる。","ENG":"Hang in there. I'll tend to your wounds.","TWN":"再忍一忍，我為你療傷。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"<color=#ffd34c>재조립</color>하면 금방 나을 거야. 머릿속의 기억이 그렇게 속삭이고 있어.","JPN":"<color=#ffd34c>組み直し</color>さえすればすぐ治る。頭の中の記憶がそうささやいている。","ENG":"You'll be all better in no time once you've been <color=#ffd34c>reassembled</color>. That's what the memories in my head are whispering.","TWN":"如果<color=#ffd34c>重新組裝</color>，馬上就會好的。腦海裡的記憶在竊竊私語。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니......","JPN":"お姉ちゃん……","ENG":"Rita...","TWN":"姐姐……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"저, 그동안 언니 말 잘 안 들었던 거...... 죄송해요.","JPN":"私、今までお姉ちゃんの言うこと、ちゃんと聞かなくて……ごめんなさい。","ENG":"I'm sorry for not listening to you... I'm sorry.","TWN":"我，一直以來都不聽姐姐的話……對不起。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"사과하지 마.","JPN":"謝るな。","ENG":"Don't be.","TWN":"別道歉。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"네가 술 냄새 나는 나도 좋아해 준 것처럼...... 나도 그런 네가 싫지 않았어.","JPN":"お前が酒臭い私でも慕ってくれたみたいに……私もそんなお前が嫌いじゃなかった。","ENG":"Just as you liked me just the way I am even when I reeked of booze... I didn't think you were half bad either.","TWN":"就像你喜歡酒氣薰天的我一樣……我也喜歡那樣的你。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TELE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>구조 신호가 접수된 좌표에 도착했습니다. 지금부터 수색을 개시합니다.</color>","JPN":"<color=#ffd34c>救助信号が寄せられた座標に到着しました。これより捜索を開始します。</color>","ENG":"<color=#ffd34c>We have arrived at the coordinates sent with the May Day message. We will now begin the search.</color>","TWN":"<color=#ffd34c>已到達求救信號提供的座標位置。現在開始搜索。</color>"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L35_1","type":"dialog","speaker":"TELE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>고밀도 침식파 관측! 미등록된 파형입니다!</color>","JPN":"<color=#ffd34c>高密度侵食波観測！　未登録波形です！</color>","ENG":"<color=#ffd34c>High-intensity Corruption Ray detected! I've never seen this type of wave before!</color>","TWN":"<color=#ffd34c>觀測到高密度侵蝕波！是未記錄過的波型！</color>"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L36_1","type":"dialog","speaker":"TELE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>앞서 도착한 함선 두 척이 격침되었다는 정보가 있습니다. 전 대원, 주의 바랍니다!</color>","JPN":"<color=#ffd34c>先に到着した艦船2隻が撃沈されたという情報があります。全隊員、ご注意ください！</color>","ENG":"<color=#ffd34c>Intel suggests two other rescue ships previously went down here. Stay frosty, everyone.</color>","TWN":"<color=#ffd34c>據悉之前到達的兩艘艦船被擊沉。全體隊員，請小心！</color>"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L37_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"......사람들이 도착했네. 나는 이만 가 봐야겠어.","JPN":"……救助隊が到着したようだ。私はもう行かないと。","ENG":"We've got company... I'd better get going.","TWN":"……救難人員他們到了，我該走了。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니...... 정말 가는 거예요?","JPN":"お姉ちゃん……本当に行っちゃうんですか？","ENG":"Rita... Are you really leaving?","TWN":"姐姐……你真的要走嗎？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"가지 마요! 제가 사람들을 설득할게요!","JPN":"行かないでください！　私がみんなを説得します！","ENG":"Don't go! I'll persuade them!","TWN":"不要走！我會說服那些人的！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니는...... 나쁜 그림자가 아니라고......","JPN":"お姉ちゃんは……悪いシャドウじゃないと……","ENG":"I'll tell them... that you're not an evil Shadow...","TWN":"我的姐姐……不是壞人暗影……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"미안하지만, 오래 가지 않아 나빠질 거야.","JPN":"すまないが、長くは持たない。","ENG":"Sorry, but that's going to change real quick.","TWN":"很抱歉，但過不了多久我就會變壞的。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"이 수정에서...... 내가 모르는 기억들이 머릿속으로 흘러 들어오고 있어.","JPN":"この水晶から……私の知らない記憶が頭の中に流れ込んできている。","ENG":"This crystal... It's feeding my mind with all sorts of new memories.","TWN":"從這水晶裡……我不知道的記憶不停湧進我的腦海中。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_TOUCH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"시간이 지나면 <color=#ffd34c>리타</color>라는 이름은 지워지겠지.","JPN":"そのうち<color=#ffd34c>リタ</color>という名前は消えてしまうだろう。","ENG":"In time, there'll be no <color=#ffd34c>Rita</color> anymore.","TWN":"慢慢地，<color=#ffd34c>麗塔</color>這個名字也會被抹殺吧。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"애초에 나는...... 이걸 담을 그릇이었을 뿐이니까.","JPN":"最初から私は……これを入れるための器にすぎないから。","ENG":"After all... I was only meant to be a vessel for something else.","TWN":"我……本就是承載這些的容器。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니......","JPN":"お姉ちゃん……","ENG":"Rita...","TWN":"姐姐……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"호라이즌을 부탁해. 그 녀석은 지금이 더 나아.","JPN":"ホライズンを頼む。あいつは今のほうがマシだ。","ENG":"Take care of Horizon, will you? She's a lot better off now.","TWN":"地平線就拜託你了，那傢伙現在好多了。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MINISTRA_HORIZON_NULL_ON","text":{"KOREA":"......내가 없더라도, 잘 지내야 돼.","JPN":"……私がいなくなっても、元気に過ごすんだぞ。","ENG":"Take good care of yourself too... even when I'm not around.","TWN":"……即使沒有我，你們也要好好的。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_HORIZON_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>조난자 1명 발견!</color>","JPN":"<color=#ffd34c>遭難者1名発見！</color>","ENG":"<color=#ffd34c>We found one!</color>","TWN":"<color=#ffd34c>發現1名遇難者！</color>"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>극심한 영양 실조 상태입니다! 의무실에 자리 준비해 두세요!</color>","JPN":"<color=#ffd34c>深刻な栄養失調状態です！　医務室にベッドを用意してください！</color>","ENG":"<color=#ffd34c>She's suffering from extreme malnutrition! Prepare a bed in the infirmary!</color>","TWN":"<color=#ffd34c>極度營養不良狀態！請在醫務室準備好位置！</color>"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"}]`);export{e as default};